import optax
import jax
import jax.numpy as jnp


def loss_fn(params, batch):
    # placeholder — replace with your model
    return jnp.mean((params['w'] @ batch['x'] - batch['y']) ** 2)


optimizer = optax.rmsprop(learning_rate=1e-3, decay=0.9, eps=1e-8)

params = {'w': jnp.ones((4, 1))}
opt_state = optimizer.init(params)


@jax.jit
def train_step(params, opt_state, batch):
    grads = jax.grad(loss_fn)(params, batch)
    updates, new_state = optimizer.update(grads, opt_state)
    new_params = optax.apply_updates(params, updates)
    return new_params, new_state


# Dummy batch
batch = {'x': jnp.ones((8, 4)), 'y': jnp.ones((8, 1))}
for _ in range(100):
    params, opt_state = train_step(params, opt_state, batch)
print("Final weight:", params['w'].flatten())
